<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(newWindow.closed); </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// false</span></span>
