<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">newWindow.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">close</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
